parameters.jsCode:
const body = $('Webhook - Evaluation').first().json.body;
let valueData = {};
try {
  valueData = JSON.parse(body.value || '{}');
} catch (e) {
  valueData = { log_id: body.log_id, ticket_id: body.ticket_id, category: body.category || 'it' };
}

return {
  json: {
    log_id: valueData.log_id || body.log_id,
    ticket_id: valueData.ticket_id || body.ticket_id,
    category: valueData.category || body.category || 'it',
    evaluation: body.evaluation,
    user_id: body.user_id,
    channel_id: body.channel_id,
    thread_ts: body.thread_ts || '',
    comment: body.comment || ''
  }
};

const data = $('Parse Value').first().json;
const category = (data.category || 'it').toLowerCase();

let tableName = 'app.helpdesk_tickets';
if (category === 'hr') tableName = 'app.hr_tickets';
else if (category === 'finance') tableName = 'app.finance_tickets';

return {
  json: {
    ...data,
    tableName
  }
};

